async function run(params, api) {
  const type = params.type || 'repositories';
  const query = encodeURIComponent(params.query);
  const limit = Math.min(params.limit || 5, 10);
  const url = 'https://api.github.com/search/' + type + '?q=' + query + '&per_page=' + limit;
  api.log('Searching GitHub: ' + type + ' / ' + params.query);
  const raw = await api.httpGet(url);
  const data = JSON.parse(raw);
  const total = data.total_count || 0;
  const items = data.items || [];
  const results = items.map(function(item) {
    if (type === 'repositories') return { name: item.full_name, stars: item.stargazers_count, language: item.language, description: (item.description || '').slice(0, 120), url: item.html_url };
    if (type === 'issues') return { title: item.title, repo: item.repository_url.split('/').slice(-2).join('/'), state: item.state, labels: item.labels.map(function(l) { return l.name; }), url: item.html_url };
    if (type === 'code') return { file: item.name, repo: item.repository.full_name, path: item.path, url: item.html_url };
    if (type === 'users') return { login: item.login, type: item.type, url: item.html_url };
    return item;
  });
  return JSON.stringify({ total_count: total, results: results }, null, 2);
}
